import React, { useState } from "react";
import { View, Text, TouchableOpacity, StyleSheet, ScrollView, Image } from "react-native";

export default function HomePage({ setIsLoggedIn }: any) {
  const [ratings, setRatings] = useState<any>({});

  const vote = (name: string) => {
    setRatings((prev: any) => ({
      ...prev,
      [name]: (prev[name] || 0) + 1,
    }));
  };

const PlayerCard = ({ name, image, position, score }: any) => (
  <View style={styles.card}>

    {/* MAIN ROW: IMAGE + INFO */}
    <View style={styles.row}>

      {/* LEFT: IMAGE + BUTTONS */}
      <View style={styles.leftSide}>
        <Image source={{ uri: image }} style={styles.image} />

        {/* VOTE BUTTONS UNDER IMAGE */}
        <View style={styles.voteRow}>
          <TouchableOpacity
            style={[styles.voteButton, { backgroundColor: "#CE1126" }]}
            onPress={() =>
              setRatings((prev: any) => ({
                ...prev,
                [name]: Math.max((prev[name] || 0) - 1, 0),
              }))
            }
          >
            <Text style={styles.voteText}>-</Text>
          </TouchableOpacity>

          <TouchableOpacity
            style={[styles.voteButton, { backgroundColor: "#0038A8" }]}
            onPress={() =>
              setRatings((prev: any) => ({
                ...prev,
                [name]: (prev[name] || 0) + 1,
              }))
            }
          >
            <Text style={styles.voteText}>+</Text>
          </TouchableOpacity>
        </View>
      </View>

      {/* RIGHT: PLAYER INFO */}
      <View style={styles.infoRight}>
        <Text style={styles.player}>{name}</Text>

        <Text style={styles.details}>
          📍 Position: {position}
        </Text>

        <Text style={styles.details}>
          🏀 Season Score: {score}
        </Text>

        <Text style={styles.rating}>
          ⭐ Rating: {ratings[name] || 0}
        </Text>
      </View>

    </View>
  </View>
);
  return (
    <ScrollView style={styles.container}>
      <Text style={styles.title}>🏀 PBA Voting Idols</Text>

      <PlayerCard
        name="Alvin Patrimonio"
        image="data:image/jpeg;base64,"
      />

      <PlayerCard
        name="Johnny Abarrientos"
        image="data:image/jpeg;base64,"
      />

      <PlayerCard
        name="June Mar Fajardo"
        image="data:image/jpeg;base64,"
      />

      <PlayerCard
        name="Scottie Thompson"
        image="data:image/jpeg;base64,"
      />

      <TouchableOpacity
        style={styles.logout}
        onPress={() => setIsLoggedIn(false)}
      >
        <Text style={{ color: "white", textAlign: "center" }}>
          LOGOUT
        </Text>
      </TouchableOpacity>
    </ScrollView>
  );
}

const styles = StyleSheet.create({
  container: {
    padding: 10,
    backgroundColor: "white",
  },

  title: {
    fontSize: 24,
    fontWeight: "bold",
    textAlign: "center",
    marginVertical: 20,
    color: "#0038A8",
  },

  card: {
  backgroundColor: "#3ac0d8",
  padding: 12,
  borderRadius: 10,
  marginBottom: 10,
  flexDirection: "column", // 👈 important
},

  row: {
    flexDirection: "row",   // 👈 IMAGE LEFT, TEXT RIGHT
    alignItems: "center",
  },

  image: {
    width: 75,
    height: 75,
    borderRadius: 10,
    marginRight: 10,
  },

 info: {
  flex: 1,
  marginBottom: 5,
},

  player: {
    fontSize: 16,
    fontWeight: "bold",
  },

  voteRow: {
  flexDirection: "row",
  justifyContent: "center",
  alignItems: "center",
  marginTop: 12,   // space below image/name
},

  voteButton: {
  width: 35,
  height: 35,
  borderRadius: 8,
  justifyContent: "center",
  alignItems: "center",
  marginHorizontal: 5,
},
  voteText: {
    color: "white",
    textAlign: "center",
    fontWeight: "bold",
  },

  logout: {
    marginTop: 20,
    backgroundColor: "#CE1126",
    padding: 15,
    borderRadius: 10,
  },
});